     6→Status::GrpcStatus Utility::httpToGrpcStatus(uint64_t http_response_status) {
     7→  // From
     8→  // https://github.com/grpc/grpc/blob/master/doc/http-grpc-status-mapping.md.
     9→  switch (http_response_status) {
    10→  case 400:
    11→    return Status::WellKnownGrpcStatus::Internal;
    12→  case 401:
    13→    return Status::WellKnownGrpcStatus::Unauthenticated;
    14→  case 403:
    15→    return Status::WellKnownGrpcStatus::PermissionDenied;
    16→  case 404:
    17→    return Status::WellKnownGrpcStatus::Unimplemented;
    18→  case 429:
    19→  case 502:
    20→  case 503:
    21→  case 504:
    22→    return Status::WellKnownGrpcStatus::Unavailable;
    23→  default:
    24→    return Status::WellKnownGrpcStatus::Unknown;
    25→  }
    26→}
