   101→absl::optional<Status::GrpcStatus>
   102→Common::getGrpcStatus(const Http::ResponseHeaderOrTrailerMap& trailers, bool allow_user_defined) {
   103→  const absl::string_view grpc_status_header = trailers.getGrpcStatusValue();
   104→  uint64_t grpc_status_code;
   105→
   106→  if (grpc_status_header.empty()) {
   107→    return absl::nullopt;
   108→  }
   109→  if (!absl::SimpleAtoi(grpc_status_header, &grpc_status_code) ||
   110→      (grpc_status_code > Status::WellKnownGrpcStatus::MaximumKnown && !allow_user_defined)) {
   111→    return {Status::WellKnownGrpcStatus::InvalidCode};
   112→  }
   113→  return {static_cast<Status::GrpcStatus>(grpc_status_code)};
   114→}
   115→
   116→absl::optional<Status::GrpcStatus> Common::getGrpcStatus(const Http::ResponseTrailerMap& trailers,
   117→                                                         const Http::ResponseHeaderMap& headers,
   118→                                                         const StreamInfo::StreamInfo& info,
   119→                                                         bool allow_user_defined) {
   120→  // The gRPC specification does not guarantee a gRPC status code will be returned from a gRPC
   121→  // request. When it is returned, it will be in the response trailers. With that said, Envoy will
   122→  // treat a trailers-only response as a headers-only response, so we have to check the following
   123→  // in order:
   124→  //   1. trailers gRPC status, if it exists.
   125→  //   2. headers gRPC status, if it exists.
   126→  //   3. Inferred from info HTTP status, if it exists.
   127→  absl::optional<Grpc::Status::GrpcStatus> optional_status;
   128→  optional_status = Grpc::Common::getGrpcStatus(trailers, allow_user_defined);
   129→  if (optional_status.has_value()) {
   130→    return optional_status;
   131→  }
   132→  optional_status = Grpc::Common::getGrpcStatus(headers, allow_user_defined);
   133→  if (optional_status.has_value()) {
   134→    return optional_status;
   135→  }
   136→  return info.responseCode() ? absl::optional<Grpc::Status::GrpcStatus>(
   137→                                   Grpc::Utility::httpToGrpcStatus(info.responseCode().value()))
   138→                             : absl::nullopt;
   139→}
