   141→std::string Common::getGrpcMessage(const Http::ResponseHeaderOrTrailerMap& trailers) {
   142→  const auto entry = trailers.GrpcMessage();
   143→  return entry ? std::string(entry->value().getStringView()) : EMPTY_STRING;
   144→}
