   146→absl::optional<google::rpc::Status>
   147→Common::getGrpcStatusDetailsBin(const Http::HeaderMap& trailers) {
   148→  const auto details_header = trailers.get(Http::Headers::get().GrpcStatusDetailsBin);
   149→  if (details_header.empty()) {
   150→    return absl::nullopt;
   151→  }
   152→
   153→  // Some implementations use non-padded base64 encoding for grpc-status-details-bin.
   154→  // This is effectively a trusted header so using the first value is fine.
   155→  auto decoded_value = Base64::decodeWithoutPadding(details_header[0]->value().getStringView());
   156→  if (decoded_value.empty()) {
   157→    return absl::nullopt;
   158→  }
   159→
   160→  google::rpc::Status status;
   161→  if (!status.ParseFromString(decoded_value)) {
   162→    return absl::nullopt;
   163→  }
   164→
   165→  return {std::move(status)};
   166→}
